      errs.date = 'Vui lòng nhập ngày khám.';
    }
    if (isNotPending && !data.hospital.trim()) {
      errs.hospital = 'Vui lòng nhập phòng khám / bệnh viện.';
    }

    setHealthCheckErrors(errs);
    return errs;
  };

