    let finalValue = value;
    if (field === 'amount') {
      finalValue = formatNumberWithDots(value);
    }
    const updated = { ...paymentForm, [field]: finalValue };
    setPaymentForm(updated);
    if (paymentTouched[field]) {
      setPaymentErrors(validatePayment(updated));
    }
  };

  const validatePayment = (data: PaymentFormData) => {
    const errs: Partial<Record<keyof PaymentFormData, string>> = {};
    if (!data.date) errs.date = 'Ngày đóng không được để trống.';
    if (!data.amount || !data.amount.trim()) errs.amount = 'Vui lòng nhập số tiền.';
    else {
      const rawAmount = parseNumberFromDots(data.amount);
      if (isNaN(Number(rawAmount)) || Number(rawAmount) <= 0) errs.amount = 'Số tiền phải là số hợp lệ.';
    }
    if (!data.receipt.trim()) errs.receipt = 'Mã biên lai không được để trống.';
    return errs;
  };

  const handlePrintPayment = (p: any) => {
    setPaymentToPrint(p);
