      toast.error('Học viên chưa được đăng ký khóa học nào!');
      return;
    }

    setIsSubmittingPayment(true);
    try {
      const stageMap: Record<string, string> = {
        'Đăng ký ban đầu': 'tuition_fee',
        'Học thực hành': 'practice_completed',
        'Thi hết môn': 'graduation_exam',
        'Thi sát hạch': 're_exam_fee',
      };

      const payload = {
        course_student_id: courseStudentId,
        payment_date: new Date(paymentForm.date).toISOString(),
        type: stageMap[paymentForm.stage] || 'other',
        is_received: true,
        received_fee: Number(parseNumberFromDots(paymentForm.amount)),
        note: paymentForm.receipt,
        stage_name: paymentForm.stage,
      };

      let res;
      if (editingPaymentId) {
        res = await updatePayment(editingPaymentId, {
          payment_date: payload.payment_date,
          received_fee: payload.received_fee,
          note: payload.note,
          stage_name: payload.stage_name,
        });
      } else {
        res = await createPayment(payload);
      }

      if (res.success) {
        toast.success(
          editingPaymentId
            ? `Đã cập nhật lịch sử đóng tiền thành công!`
            : `Đã ghi nhận đóng ${paymentForm.amount}đ thành công cho ${student.name}!`,
        );

        // Auto print
        handlePrintPayment({
          ...payload,
          _id: editingPaymentId || res.data?._id || 'NEW',
          payment_date: payload.payment_date,
          received_fee: payload.received_fee,
        });

        setPaymentForm({ ...initialPaymentState });
        setEditingPaymentId(null);
        setPaymentErrors({});
        setPaymentTouched({});

        // Refresh payment history & full data
        const studentId = student.id || (student as any)._id;
        const [paymentRes, fullDataRes] = await Promise.all([
          getPaymentsByStudent(studentId),
          getStudentById(studentId),
        ]);
        if (paymentRes.success) setPaymentHistory(paymentRes.data?.data || []);
        if (fullDataRes.success) setFullData(fullDataRes.data);
      } else {
        toast.error(res.message || 'Lỗi khi lưu giao dịch');
      }
    } catch (error) {
      console.error(error);
      toast.error('Có lỗi xảy ra, vui lòng thử lại sau.');
    } finally {
      setIsSubmittingPayment(false);
    }
