/* 7. Center Info Management */
function CenterInfoManagement() {
  const [info, setInfo] = useState({
    name: '',
    website: '',
    address: '',
    phone: '',
    email: '',
    fax: ''
  });
  const [touched, setTouched] = useState<Record<string, boolean>>({});
  const [isSaving, setIsSaving] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchSettings();
  }, []);

  const fetchSettings = async () => {
    try {
      setLoading(true);
      const res = await getSystemSettings();
      if (res.success && res.data) {
        const s = res.data;
        setInfo({
          name: s.center_name || '',
          website: s.center_website || '',
          address: s.center_address || '',
          phone: s.center_phone || '',
          email: s.center_email || '',
          fax: s.center_fax || ''
        });
      }
    } catch (error) {
      console.error('Lỗi khi tải cấu hình hệ thống:', error);
    } finally {
      setLoading(false);
    }
  };

  const errors = {
    name: touched.name && !info.name.trim() ? 'Tên trung tâm không được để trống' : '',
    website: touched.website && info.website && !/^[\w.-]+\.[a-z]{2,}$/i.test(info.website) ? 'Website không hợp lệ' : '',
    address: touched.address && !info.address.trim() ? 'Địa chỉ không được để trống' : '',
    phone: touched.phone && !/^\d{10,11}$/.test(info.phone) ? 'SĐT không hợp lệ' : '',
    email: touched.email && info.email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(info.email) ? 'Email không hợp lệ' : ''
  };

  const handleSave = async () => {
    setTouched({ name: true, website: true, address: true, phone: true, email: true });
    if (Object.values(errors).some(e => e)) {
      toast.error('Vui lòng kiểm tra lại thông tin');
      return;
    }

    setIsSaving(true);
    try {
      const res = await updateSystemSettings({
        center_name: info.name,
        center_website: info.website,
        center_address: info.address,
        center_phone: info.phone,
        center_email: info.email,
        center_fax: info.fax
      });

      if (res.success) {
        toast.success('Đã cập nhật thông tin trung tâm thành công');
      } else {
        toast.error(res.message || 'Không thể lưu thông tin');
      }
    } catch (error) {
      toast.error('Lỗi kết nối máy chủ');
    } finally {
      setIsSaving(false);
    }
  };

  if (loading) {
    return (
      <div className="bg-white border border-gray-100 rounded-3xl p-20 flex flex-col items-center justify-center gap-4">
        <div className="w-10 h-10 border-4 border-indigo-200 border-t-indigo-600 rounded-full animate-spin" />
        <p className="text-gray-400 font-bold uppercase tracking-widest text-xs">Đang tải thông tin trung tâm...</p>
      </div>
    );
  }

  return (
    <div className="bg-white border border-gray-100 rounded-3xl p-8 shadow-sm animate-in fade-in duration-300 max-w-4xl">
      <div className="flex items-center gap-2 mb-6 text-indigo-600">
        <Building2 className="w-5 h-5" />
        <h3 className="text-base font-black text-gray-800 tracking-tight uppercase">Thông tin trung tâm</h3>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
        <div className="flex flex-col gap-1.5 md:col-span-2">
          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Tên trung tâm</label>
          <input 
            type="text" 
            value={info.name} 

